import streamlit as stimport numpy as npimport matplotlib.pyplot as pltst.set_page_config(page_title="黑體輻射模擬器", layout="centered")# 物理常數h, c, kB = 6.626e-34, 3.0e8, 1.38e-23sigma = 5.67e-8T_sun = 5773P_sun = sigma * (T_sun**4)st.title("??? 黑體輻射互動模擬器")st.markdown("### 實驗數據分析")# 數值輸入框temp_k = st.number_input("輸入絕對溫度 (Kelvin):", min_value=100, max_value=20000, value=5773, step=100)# 物理計算total_intensity = sigma * (temp_k**4) [cite: 111]ratio_to_sun = total_intensity / P_sun [cite: 111]peak_wave_nm = (2.898e-3 / temp_k) * 1e9 [cite: 53]# 顯示中文資訊 (在網頁元件中顯示中文不會亂碼)col1, col2 = st.columns(2)with col1:    st.metric("坡峰波長 (Peak)", f"{peak_wave_nm:.1f} nm")    st.metric("總輻射強度", f"{total_intensity:.2e} W/m?")with col2:    st.metric("相對於太陽比值", f"{ratio_to_sun:.3f} 倍")# 繪圖waves_nm = np.linspace(50, 4000, 1000)waves_m = waves_nm * 1e-9with np.errstate(over='ignore', divide='ignore'):    intensity = (2 * h * c**2) / (waves_m**5 * (np.exp((h * c) / (waves_m * kB * temp_k)) - 1))fig, ax = plt.subplots()ax.plot(waves_nm, intensity, color='black', lw=2)# 彩虹區for w in range(400, 701):    ax.axvspan(w, w+1, color=plt.cm.rainbow((w-400)/300), alpha=0.3, lw=0)ax.set_xlabel("Wavelength (nm)")ax.set_ylabel("Spectral Radiance")ax.set_xlim(0, 3500)st.pyplot(fig)